+#[test]
+fn mock_mux_client_missing_pane() {
+    let rt = RuntimeFixture::current_thread();
+    rt.block_on(async {
+        let cx = healthy_cx();
+        let client = MockMuxClient::new();
+        let result = client.get_pane_text(&cx, 999).await;
+        assert!(result.is_err());
+    });
+}
